// ── PASTE YOUR KEY HERE ─────────────────────────
const ANTHROPIC_KEY = 'sk-ant-PASTE-YOUR-KEY-HERE';
// ─────────────────────────────────────────────────

const raw = $input.first().json;
const url = raw.body?.url || raw.url || raw.query?.url || '';
if (!url || !url.startsWith('http')) throw new Error(`URL missing. Got: "${url}"`);
return [{ json: { url: url.trim(), anthropicKey: ANTHROPIC_KEY } }];

const items = $input.all();
const markdown = items[0]?.json?.data || '';
const html     = items[1]?.json?.data || '';
const cfg      = $('⚙️ Config').first().json;

// ── COLORS ────────────────────────────────────────────────
function isNeutral(hex) {
  const r=parseInt(hex.slice(1,3),16),g=parseInt(hex.slice(3,5),16),b=parseInt(hex.slice(5,7),16);
  const max=Math.max(r,g,b),min=Math.min(r,g,b);
  const l=(max+min)/510;
  const s=max===min?0:(max-min)/(255-Math.abs(max+min-255));
  return s<0.15||l>0.93||l<0.07;
}
const seenC=new Set(); const brandColors=[];
function addColor(hex){
  if(!hex) return;
  const c=hex.toLowerCase();
  if(!seenC.has(c)&&!isNeutral(hex)&&/^#[0-9a-f]{6}$/.test(c)){seenC.add(c);brandColors.push(hex);}
}

// 1. meta theme-color
const tc=html.match(/<meta[^>]+name=["']theme-color["'][^>]+content=["']([^"']+)/i)||
          html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+name=["']theme-color["']/i);
if(tc?.[1]?.startsWith('#')) addColor(tc[1]);

// 2. SVG fill attributes (logo/icon brand colors — highest priority)
(html.match(/\bfill=["']#([0-9a-fA-F]{6})["']/g)||[]).forEach(m=>{
  const h=m.match(/#[0-9a-fA-F]{6}/)?.[0];if(h)addColor(h);
});

// 3. SVG fill as style property: fill:#rrggbb
(html.match(/\bfill\s*:\s*#([0-9a-fA-F]{6})/g)||[]).forEach(m=>{
  const h=m.match(/#[0-9a-fA-F]{6}/)?.[0];if(h)addColor(h);
});

// 4. gradient stop-color
(html.match(/stop-color\s*[=:]\s*["']?#([0-9a-fA-F]{6})/gi)||[]).forEach(m=>{
  const h=m.match(/#[0-9a-fA-F]{6}/)?.[0];if(h)addColor(h);
});

// 5. inline style attributes — any hex color value
(html.match(/style=["'][^"']*#[0-9a-fA-F]{6}[^"']*/gi)||[]).forEach(m=>{
  (m.match(/#[0-9a-fA-F]{6}/g)||[]).forEach(addColor);
});

// 6. :root / html CSS variable blocks
(html.match(/(?::root|html)\s*\{([^}]{0,3000})\}/gi)||[]).forEach(b=>{
  (b.match(/#[0-9a-fA-F]{6}\b/g)||[]).forEach(addColor);
});

// 7. named CSS custom properties (--color-*, --primary-*, etc.)
(html.match(/<style[^>]*>([\s\S]*?)<\/style>/gi)||[]).forEach(block=>{
  const vm=block.match(/--(?:color|primary|secondary|brand|accent|main|hero|dark|light|bg)[\w-]*\s*:\s*(#[0-9a-fA-F]{6})/gi)||[];
  vm.forEach(m=>{const h=m.match(/#[0-9a-fA-F]{6}/)?.[0];if(h)addColor(h);});
});

// 8. named CSS classes
(html.match(/\.(?:brand|primary|accent|main|hero|header|navbar|btn-primary|cta)[\w-]*[^{]*\{([^}]+)\}/gi)||[]).forEach(r=>{
  (r.match(/#[0-9a-fA-F]{6}\b/g)||[]).forEach(addColor);
});

// 9. frequency fallback if still sparse
if(brandColors.length<2){
  const freq={};
  (html.match(/#[0-9a-fA-F]{6}\b/g)||[]).forEach(c=>{if(!isNeutral(c))freq[c.toLowerCase()]=(freq[c.toLowerCase()]||0)+1;});
  Object.entries(freq).sort((a,b)=>b[1]-a[1]).forEach(([hex])=>addColor(hex));
}

const roles=['Primary','Secondary','Accent','Highlight','Neutral','Background'];
const palette=brandColors.slice(0,6).length>=2
  ?brandColors.slice(0,6).map((hex,i)=>({hex,name:roles[i]||'Color'}))
  :[{hex:'#1A2E44',name:'Primary'},{hex:'#C9A96E',name:'Gold Accent'},{hex:'#F8F6F1',name:'Background'}];

// ── TYPOGRAPHY ────────────────────────────────────────────
const seenF=new Set(); const fonts=[];
function addFont(raw){
  const name=decodeURIComponent(raw).replace(/\+/g,' ').replace(/:.*$/,'').replace(/["']/g,'').trim();
  if(name.length>1&&!seenF.has(name.toLowerCase())){seenF.add(name.toLowerCase());fonts.push(name);}
}
(html.match(/fonts\.googleapis\.com\/css[^"'> ]*/gi)||[]).forEach(link=>{
  [...link.matchAll(/family=([^&|:+; ">]+)/gi)].forEach(m=>addFont(m[1]));
});
(html.match(/@import\s+url\([^)]+googleapis[^)]+\)/gi)||[]).forEach(imp=>{
  [...imp.matchAll(/family=([^&|:+;"' >)]+)/gi)].forEach(m=>addFont(m[1]));
});
if(fonts.length===0)
  [...html.matchAll(/font-family\s*:\s*["']([^"']{2,40})["']/gi)].forEach(m=>addFont(m[1]));

const monoFont=fonts.find(f=>/mono|code|courier|jetbrains|fira|source/i.test(f))||'JetBrains Mono';
const nonMono=fonts.filter(f=>!/mono|code|courier|jetbrains|fira|source/i.test(f));
const typography={heading:nonMono[0]||'',body:nonMono[1]||nonMono[0]||'',mono:monoFont};

// ── SOCIAL CHANNELS ───────────────────────────────────────
const socialDefs=[
  {name:'Instagram',   icon:'instagram', color:'#E4405F', re:/instagram\.com\/([A-Za-z0-9_.]{2,30})/i},
  {name:'LinkedIn',    icon:'linkedin',  color:'#0A66C2', re:/linkedin\.com\/company\/([A-Za-z0-9_-]{2,50})/i},
  {name:'Facebook',    icon:'facebook',  color:'#1877F2', re:/facebook\.com\/([A-Za-z0-9_.]{2,50})/i},
  {name:'YouTube',     icon:'youtube',   color:'#FF0000', re:/youtube\.com\/(?:channel\/|@|user\/)([A-Za-z0-9_-]{2,50})/i},
  {name:'X / Twitter', icon:'twitter',   color:'#000000', re:/(?:twitter|x)\.com\/([A-Za-z0-9_]{2,50})/i},
  {name:'TikTok',      icon:'music',     color:'#010101', re:/tiktok\.com\/@([A-Za-z0-9_.]{2,50})/i},
];
const channels=[];
const seenSocial=new Set();
const SKIP=/^(share|intent|sharer|login|connect|authorize|platform|ads|business|about|help|legal|privacy|jobs|careers|developers|policies)$/i;
socialDefs.forEach(function(d){
  const m=html.match(d.re);
  if(m&&m[1]&&!SKIP.test(m[1])&&!seenSocial.has(d.name)){
    seenSocial.add(d.name);
    channels.push({name:d.name,icon:d.icon,color:d.color,handle:'@'+m[1],audience:''});
  }
});

// ── LOGO (first SVG inside <header>) ──────────────────────
let logoSvg='';
const headerBlock=html.match(/<header[\s\S]{0,3000}?<\/header>/i);
const svgSrc=headerBlock?headerBlock[0]:html;
const svgM=svgSrc.match(/<svg[\s\S]{10,6000}?<\/svg>/i);
if(svgM) logoSvg=svgM[0].replace(/\s+/g,' ').trim().slice(0,4000);

return [{ json: { markdown, url:cfg.url, anthropicKey:cfg.anthropicKey, palette, typography, channels, logoSvg } }];

