const rawText = $input.first().json?.content?.[0]?.text || '';
const cssData = $('Extract CSS Data').first().json;

let claudeData = {};
try {
  const cleaned = rawText.replace(/^```json?\s*/i,'').replace(/\s*```$/i,'').trim();
  claudeData = JSON.parse(cleaned);
} catch(e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) try { claudeData = JSON.parse(match[0]); } catch {}
}

// Claude handles semantic fields; CSS extraction handles visual + social fields
const result = {
  ...claudeData,
  palette:    cssData.palette,
  typography: cssData.typography,
  channels:   cssData.channels,
  logoSvg:    cssData.logoSvg,
};

if (!result.name) result.name = cssData.url.replace(/https?:\/\/(www\.)?/,'').split('/')[0];
if (!result.websiteUrl) result.websiteUrl = cssData.url;

console.log('[WF00] result:', JSON.stringify(result));
return [{ json: result }];
